INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
('Musée d''Art', 'Un musée avec des tableaux célèbres, des sculptures et des visiteurs admirant.', '"Une sculpture a des parties qui se chevauchent.\n"Les tableaux ont des couleurs qui se fondent.', 'L''art est subjectif, mais les formes impossibles et les couleurs erronées indiquent une génération IA.', 10);
INSERT INTO Jeu_chasse_anomalies (image_url, titre_image, coordonnes_anomalie_json, explication, points_accordes) VALUES
